vector<vector<int>> findZeroSumSubarrays(vector<int> nums) {
    int n = nums.size();
    vector<vector<int>> result;
    unordered_map<int, int> sumMap;
    int prefixSum = 0;
    sumMap[prefixSum] = -1;

    for (int i = 0; i < n; i++) {
        prefixSum += nums[i];
        if (sumMap.find(prefixSum) != sumMap.end()) {
            result.push_back(vector<int>(nums.begin() + sumMap[prefixSum] + 1, nums.begin() + i + 1));
        }
        sumMap[prefixSum] = i;
    }
    return result;
}

