// Solution
import java.util.ArrayList;
import java.util.Collections;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

public class Main {
    public static void main(String[] args) {
        List<Integer> nums = new ArrayList<>(Arrays.asList(4, -3, -1, -2, 5, -3, 4));
        List<List<Integer>> result = findZeroSumSubarrays(nums);
        for (List<Integer> subarray : result) {
            for (Integer num : subarray) {
                System.out.print(num + ' '); 
            }
            System.out.println();
        }
    }

    public static List<List<Integer>> findZeroSumSubarrays(List<Integer> nums) {
        int n = nums.size();
        List<List<Integer>> result = new ArrayList<>();
        Map<Integer, Integer> sumMap = new HashMap<>();
        int prefixSum = 0;
        sumMap.put(prefixSum, -1);

        for (int i = 0; i < n; i++) {
            prefixSum += nums.get(i);
            if (sumMap.containsKey(prefixSum)) {
                result.add(Collections.singletonList(nums.get(sumMap.get(prefixSum) + 1)));
                result.add(nums.subList(sumMap.get(prefixSum) + 1, i + 1));
            }
            sumMap.put(prefixSum, i);
        }
        return result;
    }
}

