def findZeroSumSubarrays(nums: List[int]) -> List[List[int]]:
    n = len(nums)
    result = []
    sumMap = {}
    prefixSum = 0
    sumMap[prefixSum] = -1

    for i in range(n):
        prefixSum += nums[i]
        if prefixSum in sumMap:
            result.append(nums[sumMap[prefixSum] + 1:i + 1])
        sumMap[prefixSum] = i
    return result

