// Solution
function findZeroSumSubarrays(nums) {
    let n = nums.length;
    let result = [];
    let sumMap = {};
    let prefixSum = 0;
    sumMap[prefixSum] = -1;

    for (let i = 0; i < n; i++) {
        prefixSum += nums[i];
        if (prefixSum in sumMap) {
            result.push(nums.slice(sumMap[prefixSum] + 1, i + 1));
        }
        sumMap[prefixSum] = i;
    }
    return result;
}

let input = readline().split(' ').map(Number);
